pub trait HpackStringEncode {
    fn hpack_encode(&self) -> Result<Vec<u8>, Error>;
}

impl HpackStringEncode for Vec<u8> {
    fn hpack_encode(&self) -> Result<Vec<u8>, Error> {
        let mut encoder = HuffmanEncoder::new();
        for code in self {
            encoder.put(*code)?;
        }
        encoder.ends()
    }
}
